INSERT INTO server_property_definitions VALUES('ai.nav_carve_min_base_size','ai','Nav Carve Min Base Size','The minimum size we allow a carving volume to be.','integer','2',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.nav_carve_min_building_blocks_to_apply_optimization','ai','Nav Carve Min Building Blocks To Apply Optimization','The minimum number of building blocks a building needs to consist of for this optimization to be applied.','integer','25',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.nav_carve_size_multiplier','ai','Nav Carve Size Multiplier','The size multiplier applied to the size of the carve volume. The smaller the value, the tighter the skirt around foundation edges, but too small and animals can attack through walls.','integer','4',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.nav_carve_use_building_optimization','ai','Nav Carve Use Building Optimization','If nav_carve_use_building_optimization is true, we attempt to reduce the amount of navmesh carves for a building.','boolean','False',NULL,NULL,1,1);
