INSERT INTO server_property_definitions VALUES('ai.npc_alertness_drain_rate','ai','Npc Alertness Drain Rate','npc_alertness_drain_rate define the rate at which we drain the alertness level of an NPC when there are no enemies in sight.','decimal','0.01',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_alertness_to_aim_modifier','ai','Npc Alertness To Aim Modifier','This is multiplied with the current alertness','decimal','0.5',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_alertness_zero_detection_mod','ai','Npc Alertness Zero Detection Mod','npc_alertness_zero_detection_mod define the threshold of visibility required to detect an enemy when alertness is zero.','decimal','0.5',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_check_spawner_is_on_navmesh','ai','Npc Check Spawner Is On Navmesh',NULL,'boolean','True',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_cover_compromised_cooldown','ai','Npc Cover Compromised Cooldown','npc_cover_compromised_cooldown defines how long a cover point is marked as compromised before it''s cleared again for selection.','integer','10',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_cover_info_tick_rate_multiplier','ai','Npc Cover Info Tick Rate Multiplier','The rate at which we gather information about available cover points. Minimum value is 1, as it multiplies with the tick-rate of the fixed AI tick rate of 0.1','integer','20',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_cover_path_vs_straight_dist_max_diff','ai','Npc Cover Path Vs Straight Dist Max Diff','npc_cover_path_vs_straight_dist_max_diff defines what the maximum difference between straight-line distance and path distance can be when evaluating cover points.','integer','2',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_cover_use_path_distance','ai','Npc Cover Use Path Distance','If npc_cover_use_path_distance is set to true then npcs will look at the distance between the cover point and their target using the path between the two, rather than the straight-line distance.','boolean','True',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_deliberate_hit_randomizer','ai','Npc Deliberate Hit Randomizer','The percentage away from a maximum miss the randomizer is allowed to travel when shooting to deliberately hit the target','decimal','0.85',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_deliberate_miss_offset_multiplier','ai','Npc Deliberate Miss Offset Multiplier','The offset with which the NPC will maximum miss the target.','decimal','1.25',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_deliberate_miss_to_hit_alignment_time','ai','Npc Deliberate Miss To Hit Alignment Time','The time it takes for the NPC to deliberately miss to the time the NPC tries to hit its target.','decimal','1.5',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_door_trigger_size','ai','Npc Door Trigger Size','npc_door_trigger_size defines the size of the trigger box on doors that opens the door as npcs walk close to it','decimal','1.5',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_enable','ai','Npc Enable','If npc_enable is set to false then npcs won''t spawn.','boolean','True',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_families_no_hurt','ai','Npc Families No Hurt','If npc_families_no_hurt is true, npcs of the same family won''t be able to hurt each other.','boolean','True',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_gun_noise_silencer_modifier','ai','Npc Gun Noise Silencer Modifier','The modifier by which a silencer reduce the noise that a gun makes when shot.','decimal','0.15',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_htn_player_base_damage_modifier','ai','Npc Htn Player Base Damage Modifier','Baseline damage modifier for the new HTN Player NPCs to nerf their damage compared to the old NPCs.','decimal','1.15',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_htn_player_frustration_threshold','ai','Npc Htn Player Frustration Threshold','npc_htn_player_frustration_threshold defines where the frustration threshold for NPCs go, where they have the opportunity to change to a more aggressive tactic.','integer','3',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_ignore_chairs','ai','Npc Ignore Chairs','If npc_ignore_chairs is true, npcs won''t care about seeking out and sitting in chairs.','boolean','True',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_junkpile_dist_aggro_gate','ai','Npc Junkpile Dist Aggro Gate','npc_junkpile_dist_aggro_gate define at what range','integer','8',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_junkpilespawn_chance','ai','Npc Junkpilespawn Chance','defines the chance for scientists to spawn at NPC junkpiles.','decimal','0.07',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_max_junkpile_count','ai','Npc Max Junkpile Count','npc_max_junkpile_count define how many npcs can spawn into the world at junkpiles at the same time','integer','30',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_max_population_military_tunnels','ai','Npc Max Population Military Tunnels','npc_max_population_military_tunnels defines the size of the npc population at military tunnels.','integer','3',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_max_roam_multiplier','ai','Npc Max Roam Multiplier','This is multiplied with the max roam range stat of an NPC to determine how far from its spawn point the NPC is allowed to roam.','integer','3',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_only_hurt_active_target_in_safezone','ai','Npc Only Hurt Active Target In Safezone','If npc_only_hurt_active_target_in_safezone is true, npcs won''t any player other than their actively targeted player when in a safe zone.','boolean','True',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_patrol_point_cooldown','ai','Npc Patrol Point Cooldown','npc_patrol_point_cooldown defines the cooldown time on a patrol point until it''s available again','integer','5',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_reasoning_system_tick_rate_multiplier','ai','Npc Reasoning System Tick Rate Multiplier','The rate at which we tick the reasoning system. Minimum value is 1, as it multiplies with the tick-rate of the fixed AI tick rate of 0.1','integer','1',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_respawn_delay_max_military_tunnels','ai','Npc Respawn Delay Max Military Tunnels','npc_respawn_delay_max_military_tunnels defines the maximum delay between spawn ticks at military tunnels.','integer','1920',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_respawn_delay_min_military_tunnels','ai','Npc Respawn Delay Min Military Tunnels','npc_respawn_delay_min_military_tunnels defines the minimum delay between spawn ticks at military tunnels.','integer','480',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_sensory_system_tick_rate_multiplier','ai','Npc Sensory System Tick Rate Multiplier','The rate at which we tick the sensory system. Minimum value is 1, as it multiplies with the tick-rate of the fixed AI tick rate of 0.1','integer','5',NULL,NULL,1,1);
