INSERT INTO server_property_definitions VALUES('ai.npc_spawn_per_tick_min_military_tunnels','ai','Npc Spawn Per Tick Min Military Tunnels','npc_spawn_per_tick_min_military_tunnels defineshow many will minimum spawn at once at military tunnels.','integer','1',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_speed_crouch_run','ai','Npc Speed Crouch Run','npc_speed_crouch_run define the speed of an npc when in the crouched run state, and should be a number between 0 and 1.','decimal','0.25',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_speed_crouch_walk','ai','Npc Speed Crouch Walk','npc_speed_walk define the speed of an npc when in the crouched walk state, and should be a number between 0 and 1.','decimal','0.1',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_speed_run','ai','Npc Speed Run','npc_speed_walk define the speed of an npc when in the run state, and should be a number between 0 and 1.','decimal','0.4',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_speed_sprint','ai','Npc Speed Sprint','npc_speed_walk define the speed of an npc when in the sprint state, and should be a number between 0 and 1.','decimal','1',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_speed_walk','ai','Npc Speed Walk','npc_speed_walk define the speed of an npc when in the walk state, and should be a number between 0 and 1.','decimal','0.18',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_use_new_aim_system','ai','Npc Use New Aim System','If npc_use_new_aim_system is true, npcs will miss on purpose on occasion, where the old system would randomize aim cone.','boolean','True',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_use_thrown_weapons','ai','Npc Use Thrown Weapons','If npc_use_thrown_weapons is true, npcs will throw grenades, etc. This is an experimental feature.','boolean','True',NULL,NULL,1,1);
INSERT INTO server_property_definitions VALUES('ai.npc_valid_aim_cone','ai','Npc Valid Aim Cone','npc_valid_aim_cone defines how close their aim needs to be on target in order to fire.','decimal','0.8',NULL,NULL,1,1);
