INSERT INTO server_property_definitions VALUES('aimanager.ai_dormant','aimanager','Ai Dormant','If ai_dormant is true, any npc outside the range of players will render itself dormant and take up less resources, but wildlife won''t simulate as well.','boolean','True',NULL,NULL,1,0);
INSERT INTO server_property_definitions VALUES('aimanager.ai_dormant_max_wakeup_per_tick','aimanager','Ai Dormant Max Wakeup Per Tick','ai_dormant_max_wakeup_per_tick defines the maximum number of dormant agents we will wake up in a single tick.','integer','30',NULL,NULL,1,0);
INSERT INTO server_property_definitions VALUES('aimanager.ai_htn_animal_tick_budget','aimanager','Ai Htn Animal Tick Budget','ai_htn_animal_tick_budget defines the maximum amount of milliseconds ticking htn animal agents are allowed to consume.','integer','4',NULL,NULL,1,0);
INSERT INTO server_property_definitions VALUES('aimanager.ai_htn_player_junkpile_tick_budget','aimanager','Ai Htn Player Junkpile Tick Budget','ai_htn_player_junkpile_tick_budget defines the maximum amount of milliseconds ticking htn player junkpile agents are allowed to consume.','integer','4',NULL,NULL,1,0);
INSERT INTO server_property_definitions VALUES('aimanager.ai_htn_player_tick_budget','aimanager','Ai Htn Player Tick Budget','ai_htn_player_tick_budget defines the maximum amount of milliseconds ticking htn player agents are allowed to consume.','integer','4',NULL,NULL,1,0);
INSERT INTO server_property_definitions VALUES('aimanager.ai_htn_use_agency_tick','aimanager','Ai Htn Use Agency Tick','If ai_htn_use_agency_tick is true, the ai manager''s agency system will tick htn agents at the ms budgets defined in ai_htn_player_tick_budget and ai_htn_animal_tick_budget. If it''s false, each agent registers with the invoke system individually, with no frame-budget restrictions.','boolean','True',NULL,NULL,1,0);
INSERT INTO server_property_definitions VALUES('aimanager.ai_to_player_distance_wakeup_range','aimanager','Ai To Player Distance Wakeup Range','If an agent is beyond this distance to a player, it''s flagged for becoming dormant.','integer','160',NULL,NULL,1,0);
INSERT INTO server_property_definitions VALUES('aimanager.nav_disable','aimanager','Nav Disable','If set to true the navmesh won''t generate.. which means Ai that uses the navmesh won''t be able to move','boolean','False',NULL,NULL,1,0);
INSERT INTO server_property_definitions VALUES('aimanager.nav_obstacles_carve_state','aimanager','Nav Obstacles Carve State','nav_obstacles_carve_state defines which obstacles can carve the terrain. 0 - No carving, 1 - Only player construction carves, 2 - All obstacles carve.','integer','2',NULL,NULL,1,0);
INSERT INTO server_property_definitions VALUES('aimanager.nav_wait','aimanager','Nav Wait','If true we''ll wait for the navmesh to generate before completely starting the server. This might cause your server to hitch and lag as it generates in the background.','boolean','True',NULL,NULL,1,0);
INSERT INTO server_property_definitions VALUES('aimanager.pathfindingiterationsperframe','aimanager','Pathfindingiterationsperframe','The maximum amount of nodes processed each frame in the asynchronous pathfinding process. Increasing this value will cause the paths to be processed faster, but can cause some hiccups in frame rate. Default value is 100, a good range for tuning is between 50 and 500.','integer','100',NULL,NULL,1,0);
INSERT INTO server_property_definitions VALUES('aimanager.setdestination_navmesh_failsafe','aimanager','Setdestination Navmesh Failsafe','If set to true, npcs will attempt to place themselves on the navmesh if not on a navmesh when set destination is called.','boolean','False',NULL,NULL,1,0);
